Use MAUI's `Window` lifecycle events combined with `Preferences` for lightweight persistence:

```csharp
// NotePage.xaml.cs
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();
    }

    protected override void OnAppearing()
    {
        base.OnAppearing();

        // Restore draft when page appears
        if (Preferences.ContainsKey(DraftKey))
            NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    // Hook into Window lifecycle for background/resume
    protected override void OnHandlerChanged()
    {
        base.OnHandlerChanged();

        if (Window is not null)
        {
            Window.Deactivated += OnAppBackgrounded;
            Window.Activated += OnAppResumed;
        }
    }

    private void OnAppBackgrounded(object? sender, EventArgs e)
    {
        // Save draft immediately when app loses focus
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    private void OnAppResumed(object? sender, EventArgs e)
    {
        // Optionally refresh from storage on resume
        NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    public void ClearDraft()
    {
        // Call this after the user explicitly saves/discards
        Preferences.Remove(DraftKey);
    }
}
```

```xml
<!-- NotePage.xaml (relevant part) -->
<Editor x:Name="NoteEditor"
        Placeholder="Start typing your note..." />
```

**Key points:**

- **`Window.Deactivated`** fires when the app goes to the background — save here
- **`Window.Activated`** fires on resume — restore here
- **`Preferences`** is ideal for small text; for large content, use `SecureStorage` or file I/O instead
- Call `ClearDraft()` after the user intentionally saves or discards, so stale drafts don't persist
